devicemanagement_pair_wizard_title_executed = TextObject(bs_BA="Povezivanje glavnog uređaja uspješno izvršeno", cs_CZ="Připojení hlavního zařízení úspěšně provedeno", da_DK="Oprettelse af forbindelse for primært apparat gennemført korrekt", de_DE="Hauptgerätverbindung erfolgreich durchgeführt", el_GR="Η σύνδεση της βασικής συσκευής πραγματοποιήθηκε με επιτυχία", en_GB="Main device connected successfully", es_ES="El dispositivo principal se ha conectado correctamente", fi_FI="Päälaitteen yhdistäminen onnistui", fr_FR="Périphérique principal connecté avec succès", hr_HR="Spajanje glavnog uređaja uspješno je provedeno", hu_HU="A főkészülék összekapcsolása sikeresen végrehajtva", it_IT="Dispositivo principale collegato correttamente", nl_NL="Verbinding hoofdapparaat tot stand gebracht", no_NO="Det er opprettet forbindelse med hovedenheten", pl_PL="Podłączanie urządzenia głwnego przeprowadzone pomyślnie", pt_PT="Ligação ao aparelho principal realizada com sucesso", ro_RO="Conectarea dispozitivului principal realizată cu succes", ru_RU="Подключение основного устройства успешно выполнено", sk_SK="Pripojenie hlavného zariadenia sa úspešne vykonalo", sl_SI="Glavna naprava je bila uspešno povezana", sr_RS="Povezivanje glavnog uređaja uspešno izvršeno", sv_SE="Huvudenheten är nu ansluten", tr_TR="Ana cihaz bağlantısı başarıyla uygulandı", uk_UA="Підключення основного пристрою успішно виконано")
