devicemanagement_pair_wizard_title_start = TextObject(bs_BA="Pokretanje povezivanja s glavnim uređajem", cs_CZ="Zahájit připojování hlavního zařízení", da_DK="Start oprettelse af forbindelse for primært apparat", de_DE="Hauptgerätverbindung starten", el_GR="Έναρξη σύνδεσης βασικής συσκευής", en_GB="Start main device connection", es_ES="Conectar dispositivo principal", fi_FI="Käynnistä päälaitteen yhdistäminen", fr_FR="Lancer la connexion du périphérique principal", hr_HR="Pokrenuti spajanje glavnog uređaja", hu_HU="A főkészülék csatlakoztatásának indítása", it_IT="Avvia collegamento del dispositivo principale", nl_NL="Verbinding met hoofdapparaat maken", no_NO="Start opprettelse av hovedenhetforbindelse", pl_PL="Uruchom podłączanie urządzenia głównego", pt_PT="Iniciar ligação do aparelho principal", ro_RO="Iniţiere conectare dispozitiv principal", ru_RU="Начать подключение основного устройства", sk_SK="Spustiť pripojenie hlavného zariadenia", sl_SI="Zagon povezovanja glavne naprave", sr_RS="Pokretanje povezivanja sa glavnim uređajem", sv_SE="Starta anslutning till huvudenhet", tr_TR="Ana cihaz bağlantısını başlat", uk_UA="Розпочати підключення основного пристрою")
devicemanagement_unpair_wizard_confirm_text = TextObject(bs_BA="Prilikom odvajanja glavnog uređaja, brišu se svi digitalni ključevi i više se ne mogu koristiti kao ključevi vozila.\nDa li zaista želite odvojiti glavni uređaj?", cs_CZ="Při odpojení hlavního zařízení se všechny digitální klíčky smažou a nebude je již možné používat jako\nklíčky od vozidla.\n\nChcete hlavní zařízení opravdu odpojit?", da_DK="Når det primære apparat afbrydes, slettes alle digitale nøgler, og de kan ikke længere anvendes som bilnøgler.\n\nVil du virkelig afbryde det primære apparat.", de_DE="Beim Trennen des Hauptgeräts werden alle digitalen Schlüssel gelöscht und können nicht mehr als\nFahrzeugschlüssel genutzt werden.\n\nMöchtest du das Hauptgerät wirklich trennen?", el_GR="Κατά την αποσύνδεση της βασικής συσκευής θα διαγραφούν όλα τα ψηφιακά κλειδιά και δεν θα μπορούν πλέον να\nχρησιμοποιηθούν ως κλειδιά οχήματος.\n\nΘέλετε σίγουρα να αποσυνδέσετε τη βασική συσκευή;", en_GB="If you remove the main device, all digital keys will be deleted and can no longer be used as vehicle keys.\n\nDo you really want to remove the main device?", es_ES="Al desconectar el dispositivo principal se borran todas las llaves digitales y ya no se pueden utilizar como\nllave del vehículo.\n\n¿Realmente desea desconectar el dispositivo principal?", fi_FI="Kun päälaite erotetaan, kaikki digitaaliset avaimet poistetaan eikä niitä voi enää käyttää autonavaimina.\n\nHaluatko varmasti erottaa päälaitteen?", fr_FR="Lors de la déconnexion du périphérique principal toutes les clés numériques sont effacées et ne peuvent plus être\nutilisées comme clés du véhicule.\n\nSouhaitez-vous vraiment déconnecter le périphérique principal?", hr_HR="Kod odvajanja glavnog uređaja svi se digitalni ključevi brišu i više se ne mogu koristiti kao ključevi vozila.\n\nŽelite li uistinu odvojiti glavni uređaj?", hu_HU="A főkészülék leválasztásakor az összes digitális kulcs törlődik, és ezután már nem használható járműkulcsként.\n\nBiztosan le szeretnéd választani a főkészüléket?", it_IT="Scollegando il dispositivo principale, tutte le chiavi digitali verranno cancellate e non potranno più essere utilizzate\ncome chiavi della vettura.\n\nDesidera davvero scollegare il dispositivo principale?", nl_NL="Bij het ontkoppelen van het hoofdapparaat worden alle digitale sleutels gewist en kunnen er niet meer dan\nvoertuigsleutels worden gebruikt.\n\nWil je het hoofdapparaat echt loskoppelen?", no_NO="Når hovedenheten kobles fra, blir alle digitale nøkler slettet og kan ikke lenger brukes som bilnøkkel.\n\nEr du sikker på at du vil koble fra hovedenheten?", pl_PL="Przy odłączeniu urządzenia głównego wszystkie kluczyki cyfrowe zostaną usunięte i nie będzie można korzystać z\nnich jako kluczyków do pojazdu.\n\nCzy na pewno chcesz odłączyć urządzenie główne?", pt_PT="Ao desligar o aparelho principal todas as chaves digitais serão eliminadas e já não podem ser utilizadas como\nchave do veículo.\n\nDesejas mesmo desligar o aparelho principal?", ro_RO="La deconectarea dispozitivului principal, toate cheile digitale vor fi şterse şi nu vor mai putea fi utilizate ca şi cheie\na autovehiculului.\n\nDoriţi într-adevăr să deconectaţi dispozitivul principal?", ru_RU="При разъединении подключения основного устройства все цифровые ключи удаляются и больше не могут\nиспользоваться в качестве ключей автомобиля.\n\nВы действительно хотите разъединить подключение основного устройства?", sk_SK="Pri odpájaní hlavného zariadenia sa všetky digitálne kľúče vymažú a už sa nie je možné ich použiť ako kľúče od\nvozidla. Skutočne chcete odpojiť hlavné zariadenie?", sl_SI="Pri prekinitvi povezave z glavno napravo se vsi digitalni ključi izbrišejo in jih ni več mogoče uporabljati\nkot ključ vozila.\n\nAli res želite prekiniti povezavo z glavno napravo?", sr_RS="Prilikom odvajanja glavnog uređaja, brišu se svi digitalni ključevi i više se ne mogu koristiti kao ključevi vozila.\nDa li zaista želite odvojiti glavni uređaj?", sv_SE="När huvudenheten ansluts raderas alla digitala nycklar och kan inte längre användas som fordonsnyckel.\n\nVill du verkligen koppla från huvudenheten?", tr_TR="Ana cihazın ayrılması sırasında tüm dijital anahtarlar silinir ve artık araç anahtarı olarak kullanılamazlar.\n\nAna cihazı gerçekten ayırmak istiyor musun?", uk_UA="У разі роз’єднання підключення основного пристрою всі цифрові ключі видаляються і більше не можуть\nвикористовуватися як ключі від автомобіля. Дійсно роз'єднати підключення основного пристрою?")
