no_connect_key_available_subtext = TextObject(bs_BA="U vozilu nije prepoznat digitalni ključ.", cs_CZ="Nebyl zjištěn žádný digitální klíček ve vozidle.", da_DK="Der blev ikke registreret nogen digital nøgle i bilen.", de_DE="Es wurde kein digitaler Schlüssel im Fahrzeug erkannt.", el_GR="Δεν αναγνωρίστηκε ψηφιακό κλειδί μέσα στο όχημα.", en_GB="No digital key was detected in the vehicle.", es_ES="No se ha detectado ninguna llave digital en el vehículo.", fi_FI="Autossa ei havaittu digitaalista avainta.", fr_FR="Aucune clé numérique n'a été détectée dans le véhicule.", hr_HR="U vozilu nije prepoznat digitalni ključ.", hu_HU="Nincs felismerve digitális kulcs a járműben.", it_IT="Non è stata rilevata alcuna chiave digitale nella vettura.", nl_NL="Er is geen digitale sleutel in het voertuig herkend.", no_NO="Ingen digital nøkkel er registrert i bilen.", pl_PL="W samochodzie nie wykryto kluczyka cyfrowego.", pt_PT="Não foi reconhecida qualquer chave digital no veículo.", ro_RO="Nu s-a detectat nicio cheie digitală în autovehicul.", ru_RU="Цифровой ключ в автомобиле не распознан.", sk_SK="Vo vozidle nebol rozpoznaný žiadny digitálny kľúč.", sl_SI="Sistem v vozilu ni zaznal nobenega digitalnega ključa.", sr_RS="U vozilu nije prepoznat digitalni ključ.", sv_SE="Ingen digital nyckel registrerades i bilen.", tr_TR="Araçta herhangi bir dijital anahtar tanınmadı.", uk_UA="Цифровий ключ в автомобілі не розпізнано.")
