texttool_globals_notification_message___sharing_pw_required = TextObject(bs_BA="Unesite lozinku za aktiviranje da bi pokrenuli vozilo.", cs_CZ="Zadejte prosím své aktivační heslo ke startování vozidla.", da_DK="Angiv dit aktiveringspassword for at starte bilen.", de_DE="Bitte gib dein Aktivierungspasswort ein, um das Fahrzeug\nzu starten.", el_GR="Καταχωρ.τ.κωδ.πρόσβ.ενεργοπ.σας, για να εκκινήσετε το\nόχημα.", en_GB="Please enter your activation password to start the vehicle.", es_ES="Por favor, introduzca su contraseña de activación para\narrancar el vehículo.", fi_FI="Syötä aktivointisalasana auton käynnistystä varten.", fr_FR="Veuillez entrer votre mot de passe d'activation pour\ndémarrer le véhicule.", hr_HR="Unesite svoju lozinku za aktiviranje kako biste pokrenuli\nvozilo.", hu_HU="A jármű elindításához add meg az aktiválási jelszavad.", it_IT="Immettere la password di attivazione per avviare la\nvettura.", nl_NL="Voer alsjeblieft je activeringswachtwoord in om het\nvoertuig te starten.", no_NO="Legg inn aktiveringspassordet for å starte bilen.", pl_PL="Proszę wprowadzić hasło aktywacyjne, aby uruchomić\npojazd.", pt_PT="Por favor, introduz a tua palavra-passe de ativação para\nligar o veículo.", ro_RO="Introduceţi parola dumneavoastră de activare, pentru a\nporni autovehiculul.", ru_RU="Пожалуйста, введите пароль активации, чтобы завести\nавтомобиль.", sk_SK="Aby ste naštartovali vozidlo, zadajte svoje aktivačné heslo.", sl_SI="Za zagon vozila vnesite svoje geslo za aktivacijo.", sr_RS="Unesite lozinku za aktiviranje da bi pokrenuli vozilo.", sv_SE="Ange aktiveringslösenordet för att starta bilen.", tr_TR="Aracı başlatmak için, lütfen aktivasyon şifreni gir.", uk_UA="Будь ласка, введіть пароль активації, щоб завести\nавтомобіль.")
texttool_globals_notification_message___smartcard_activation_error = TextObject(bs_BA="Pokušajte ponovo.", cs_CZ="Zkuste to prosím znovu.", da_DK="Forsøg igen.", de_DE="Bitte versuche es erneut.", el_GR="Προσπαθήστε πάλι.", en_GB="Please try again.", es_ES="Por favor, inténtelo de nuevo.", fi_FI="Yritä uudelleen.", fr_FR="Veuillez réessayer.", hr_HR="Pokušajte ponovno.", hu_HU="Kérünk, próbáld meg újra.", it_IT="Riprovi, per favore.", nl_NL="Probeer het alsjeblieft opnieuw.", no_NO="Prøv på nytt.", pl_PL="Proszę spróbować ponownie.", pt_PT="Por favor, tenta novamente.", ro_RO="Reîncercaţi.", ru_RU="Пожалуйста, попробуйте еще раз.", sk_SK="Prosím pokúste sa znova.", sl_SI="Poskusite znova.", sr_RS="Pokušajte ponovo.", sv_SE="Försök igen.", tr_TR="Lütfen yeniden dene.", uk_UA="Будь ласка, спробуйте ще раз.")
texttool_globals_notification_message___smartcard_activation_success = TextObject(bs_BA="Kartica ključa se automatski deaktivira korištenjem\ndigitalnog ključa ili daljinskog ključa.", cs_CZ="Karta se deaktivuje automaticky použitím digitálního\nklíčku nebo rádiového klíčku.", da_DK="Nøglekort deaktiveres automatisk ved anvendelse af\nen digital nøgle eller en nøgle med fjernbetjening.", de_DE="Schlüsselkarte wird automatisch durch die Nutzung eines\ndigitalen Schlüssels oder eines Funkschlüssels deaktiviert.", el_GR="Η κάρτα κωδικού απενεργοπ. αυτομάτως με τη χρήση ενός\nψηφ. κλειδιού ή ενός κλειδιού ασύρματου τηλεχειρισμού.", en_GB="The key card is deactivated automatically if a digital key or\na remote control key is used.", es_ES="La tarjeta llave se desactiva automáticamente al utilizar\nuna llave digital o una llave de control remoto.", fi_FI="Avainkortti deaktivoituu automaattisesti, kun digitaalista\navainta tai kauko-ohjausavainta käytetään.", fr_FR="La carte clé est automatiquement désactivée lorsqu'une\nclé numérique ou une clé à radiocommande est utilisée.", hr_HR="Kartični ključ se deaktivira automatski korištenjem\ndigitalnog ključa ili ključa na radiosignal.", hu_HU="A kulcskártya automatikusan deaktiválódik egy digitális\nvagy távirányítós kulcs használatával.", it_IT="La scheda chiave si disattiva automaticamente quando si\nutilizza una chiave digitale o una chiave con telecomando.", nl_NL="Sleutelkaart wordt door gebruik van een digitale sleutel of\neen afstandbedieningsleutel gedeactiveerd.", no_NO="Nøkkelkortet deaktiveres automatisk når du\nbruker en digital nøkkel eller fjernkontrollnøkkel.", pl_PL="Karta kluczyka zostaje automatycznie dezaktywowana\nprzez użycie kluczyka cyfrowego lub bezprzewodowego.", pt_PT="Cartão chave será automat. desativado com a utilização\nde uma chave digital ou de uma chave de ignição.", ro_RO="Cardul de acces este dezactivat automat prin utilizarea\nunei chei digitale sau a unei chei cu telecomandă.", ru_RU="Ключ-карта автоматически дезактивируется с помощью\nцифрового ключа или радиоключа.", sk_SK="Karta s kľúčom sa automaticky deaktivuje použitím\ndigitálneho kľúča alebo kľúča s diaľkovým ovládaním.", sl_SI="Kontaktna kartica se avtomatsko deaktivira,\nko uporabite digitalni ali radijski ključ.", sr_RS="Ključ-kartica se automatski deaktivira korišćenjem\ndigitalnog ključa ili daljinskog ključa.", sv_SE="Nyckelkortet avaktiveras automatiskt vid användning av\nen digital nyckel eller en fjärrnyckel.", tr_TR="Anahtar kartı, bir dijital anahtarın veya bir telsiz anahtarın\nkullanılması ile otomatik olarak devre dışı bırakılır.", uk_UA="Ключ-карта автоматично дезактивується за допомогою\nцифрового ключа або радіоключа.")
